// Si viene como string, lo parseamos
let data = msg.payload;

if (typeof data === "string") {
    data = JSON.parse(data);
}

// --- Escalado de presión: 0–1100 (raw) -> rango real del sensor en PSI ---
const IN_MIN  = 300;
const IN_MAX  = 1100;
const OUT_MIN = 200;    // <-- ajusta al mínimo real del sensor (PSI)
const OUT_MAX = 3000;   // <-- ajusta al máximo real del sensor (PSI)

let rawPressure = Number(data.pressure);
// Clamp para que nunca salga del rango de entrada
rawPressure = Math.max(IN_MIN, Math.min(IN_MAX, rawPressure));

// Mapeo lineal 0–1100  ->  OUT_MIN–OUT_MAX
let pressure = OUT_MIN + (rawPressure - IN_MIN) * (OUT_MAX - OUT_MIN) / (IN_MAX - IN_MIN);

// Resto de los valores
let temperature = data.temperature;

// Convertimos vibración a un único valor (magnitud)
let vibration = Number(data.vibration);   // ya en mm/s RMS

let floww = data.floww;

// Construcción del payload final
msg.payload = {
    timestamp: Date.now(),
    well_id: data.well_id || "WELL-01",
    _trueLabel: data._trueLabel,
    sensors: {
        pressure: pressure,
        temperature: temperature,
        vibration: vibration,
        floww: floww
    }
};

return msg;

const EXPECTED_TOKEN = env.get("WELL_TOKEN") || "well01-secret-2024";

let data = msg.payload;

// El mqtt in puede entregar string u objeto segun config -> normalizamos
if (typeof data === "string") {
    try {
        data = JSON.parse(data);
    } catch (e) {
        msg._auth = "invalid_json";
        node.warn("Mensaje MQTT descartado: JSON invalido");
        return msg;
    }
}

// Validacion del token
if (!data || typeof data !== "object" || !data.token) {
    msg._auth = "missing_token";
    node.warn("Mensaje MQTT descartado: sin token");
    return msg;
}

if (data.token !== EXPECTED_TOKEN) {
    msg._auth = "bad_token";
    node.warn("Mensaje MQTT descartado: token incorrecto");
    return msg;
}

// Token OK. Quitamos el token del payload para que no viaje por el resto del flow.
delete data.token;

// Extract ground-truth label from SKAB columns before they are dropped downstream.
// anomaly=1 -> anomaly | changepoint=1 (anomaly=0) -> warning | both 0 -> normal
if (data.anomaly !== undefined) {
    msg._trueLabel = Number(data.anomaly) === 1 ? "anomaly" : "normal";
}

if (msg._trueLabel === undefined) {
    node.warn("[WARN] anomaly/changepoint missing from MQTT payload. Fields: " + Object.keys(data).join(","));
}

msg.payload = data;
msg.payload._trueLabel = msg._trueLabel;
msg._auth = "ok";

return msg;

let buffer = flow.get("well_buffer") || [];

buffer.push(msg.payload);

if (buffer.length < 10) {
    flow.set("well_buffer", buffer);
    return null;
}

// Majority-vote _trueLabel from the 10 accumulated samples
let labelCounts = { normal: 0, anomaly: 0 };
buffer.forEach(function(s) {
    if (s._trueLabel && labelCounts[s._trueLabel] !== undefined) {
        labelCounts[s._trueLabel]++;
    }
});
msg._trueLabel = labelCounts.anomaly >= labelCounts.normal ? "anomaly" : "normal";

// Strip _trueLabel from samples so it doesn't reach Calculo de features
let samples = buffer.map(function(s) {
    let clean = Object.assign({}, s);
    delete clean._trueLabel;
    return clean;
});

// Reset buffer for next fixed window
flow.set("well_buffer", []);

msg.payload = {
    well_id: msg.payload.well_id,
    window_size: samples.length,
    ready: true,
    samples: samples
};

return msg;

let data = msg.payload.samples;

function avg(arr, key) {
    return arr.reduce((sum, item) => sum + item.sensors[key], 0) / arr.length;
}

function std(arr, key, mean) {
    let variance = arr.reduce((sum, item) => {
        let diff = item.sensors[key] - mean;
        return sum + diff * diff;
    }, 0) / arr.length;
    return Math.sqrt(variance);
}

function minVal(arr, key) {
    return Math.min(...arr.map(item => item.sensors[key]));
}

function maxVal(arr, key) {
    return Math.max(...arr.map(item => item.sensors[key]));
}

function trend(arr, key) {
    return arr[arr.length - 1].sensors[key] - arr[0].sensors[key];
}

let pressure_avg = avg(data, "pressure");
let pressure_std = std(data, "pressure", pressure_avg);
let pressure_min = minVal(data, "pressure");
let pressure_max = maxVal(data, "pressure");
let pressure_trend = trend(data, "pressure");

let temperature_avg = avg(data, "temperature");
let temperature_std = std(data, "temperature", temperature_avg);
let temperature_min = minVal(data, "temperature");
let temperature_max = maxVal(data, "temperature");
let temperature_trend = trend(data, "temperature");

let vibration_avg = avg(data, "vibration");
let vibration_std = std(data, "vibration", vibration_avg);
let vibration_min = minVal(data, "vibration");
let vibration_max = maxVal(data, "vibration");
let vibration_trend = trend(data, "vibration");

let flow_avg = avg(data, "floww");
let flow_std = std(data, "floww", flow_avg);
let flow_min = minVal(data, "floww");
let flow_max = maxVal(data, "floww");
let flow_trend = trend(data, "floww");

msg.payload = {
    well_id: msg.payload.well_id,
    timestamp: data[data.length - 1].timestamp,
    window_size: data.length,
    features: {
        pressure_avg: pressure_avg,
        pressure_std: pressure_std,
        pressure_min: pressure_min,
        pressure_max: pressure_max,
        pressure_trend: pressure_trend,

        temperature_avg: temperature_avg,
        temperature_std: temperature_std,
        temperature_min: temperature_min,
        temperature_max: temperature_max,
        temperature_trend: temperature_trend,

        vibration_avg: vibration_avg,
        vibration_std: vibration_std,
        vibration_min: vibration_min,
        vibration_max: vibration_max,
        vibration_trend: vibration_trend,

        flow_avg: flow_avg,
        flow_std: flow_std,
        flow_min: flow_min,
        flow_max: flow_max,
        flow_trend: flow_trend
    }
};

return msg;

if (!flow.get("nnReady")) {
    node.warn("MLP not ready -- training in progress");
    return null;
}

let f = msg.payload.features;

// Normalize raw sensor features to [0,1] matching the training data space.
const P  = { min: 200, range: 2800 };
const T  = { min: 50,  range: 80   };
const V  = { min: 0,   range: 40   };
const FL = { min: 0,   range: 100  };

function nAvg(v, r)   { return Math.max(0, Math.min(1, (v - r.min) / r.range)); }
function nStd(v, r)   { return Math.max(0, Math.min(1, v * 2 / r.range)); }
function nTrend(v, r) { return Math.max(0, Math.min(1, (v / r.range + 1) / 2)); }

flow.set("last_features_payload", msg.payload);

msg.runData = {
    p_avg:   nAvg(f.pressure_avg, P),     p_std: nStd(f.pressure_std, P),
    p_min:   nAvg(f.pressure_min, P),     p_max: nAvg(f.pressure_max, P),
    p_trend: nTrend(f.pressure_trend, P),

    t_avg:   nAvg(f.temperature_avg, T),   t_std: nStd(f.temperature_std, T),
    t_min:   nAvg(f.temperature_min, T),   t_max: nAvg(f.temperature_max, T),
    t_trend: nTrend(f.temperature_trend, T),

    v_avg:   nAvg(f.vibration_avg, V),     v_std: nStd(f.vibration_std, V),
    v_min:   nAvg(f.vibration_min, V),     v_max: nAvg(f.vibration_max, V),
    v_trend: nTrend(f.vibration_trend, V),

    f_avg:   nAvg(f.flow_avg, FL),         f_std: nStd(f.flow_std, FL),
    f_min:   nAvg(f.flow_min, FL),         f_max: nAvg(f.flow_max, FL),
    f_trend: nTrend(f.flow_trend, FL)
};

return msg;

let out = msg.decision;

if (!out || typeof out !== 'object' || (!('normal' in out) && !('warning' in out) && !('anomaly' in out))) {
    return null;
}

let bestLabel = null;
let bestScore = -Infinity;

for (let label in out) {
    if (out[label] > bestScore) {
        bestScore = out[label];
        bestLabel = label;
    }
}

let original = flow.get("last_features_payload") || {};

msg.payload = {
    well_id: original.well_id || "WELL-01",
    timestamp: Date.now(),
    status: bestLabel,
    confidence: bestScore,
    nn_output: out,
    features: original.features
};

return msg;

flow.set("nnReady", false);
flow.set("liveCM", null);

const candidates = [
    "C:/Users/Catan/.node-red/skab_traindata.json",
    "skab_traindata.json"
];

let raw = null, loadedFrom = null;
for (let p of candidates) {
    try {
        if (fs.existsSync(p)) {
            raw = JSON.parse(fs.readFileSync(p, "utf8"));
            loadedFrom = p;
            break;
        }
    } catch(e) { node.warn("Failed: " + p + " - " + e.message); }
}
if (!raw || raw.length === 0) { node.error("skab_traindata.json not found."); return null; }

function seqStats(steps, key) {
    let vals = steps.map(s => s[key]);
    let n = vals.length;
    let avg = vals.reduce((s, v) => s + v, 0) / n;
    let std = Math.sqrt(vals.reduce((s, v) => s + (v - avg) * (v - avg), 0) / n);
    return { avg, std, min: Math.min.apply(null, vals), max: Math.max.apply(null, vals), trend: vals[n - 1] - vals[0] };
}
function nStd(v)   { return Math.max(0, Math.min(1, v * 2)); }
function nTrend(v) { return Math.max(0, Math.min(1, (v + 1) / 2)); }
function clamp(v)  { return Math.max(0, Math.min(1, v)); }

let dataset = raw.map(sample => {
    let s = sample.input;
    let p = seqStats(s, "pressure"), t = seqStats(s, "temperature"),
        v = seqStats(s, "vibration"), fl = seqStats(s, "flow");
    return {
        input: {
            p_avg: clamp(p.avg),   p_std: nStd(p.std),   p_min: clamp(p.min),   p_max: clamp(p.max),   p_trend: nTrend(p.trend),
            t_avg: clamp(t.avg),   t_std: nStd(t.std),   t_min: clamp(t.min),   t_max: clamp(t.max),   t_trend: nTrend(t.trend),
            v_avg: clamp(v.avg),   v_std: nStd(v.std),   v_min: clamp(v.min),   v_max: clamp(v.max),   v_trend: nTrend(v.trend),
            f_avg: clamp(fl.avg),  f_std: nStd(fl.std),  f_min: clamp(fl.min),  f_max: clamp(fl.max),  f_trend: nTrend(fl.trend)
        },
        output: sample.output
    };
});

for (let i = dataset.length - 1; i > 0; i--) {
    let j = Math.floor(Math.random() * (i + 1));
    [dataset[i], dataset[j]] = [dataset[j], dataset[i]];
}

let splitIdx = Math.floor(dataset.length * 0.8);
let trainSet = dataset.slice(0, splitIdx);
let evalSet  = dataset.slice(splitIdx);
flow.set("evalSet", evalSet);

let counts = { normal: 0, anomaly: 0 };
trainSet.forEach(s => {
    if (s.output.normal === 1) counts.normal++;
    else counts.anomaly++;
});
node.log("Train: " + trainSet.length + " [N=" + counts.normal + " A=" + counts.anomaly + "] | Eval holdout: " + evalSet.length);
msg.trainData = trainSet;
return msg;

let t = context.get("t") || 0;
t += 1;
context.set("t", t);

let isAnomaly = false;

// anomaly window every 90 seconds, lasting 20 seconds
if ((t % 70) >= 20 && (t % 70) < 40) {
    isAnomaly = true;
}

let pressure;
let temperature;
let vibration;
let floww;

if (!isAnomaly) {
    pressure = 1000 + Math.random() * 50;
    temperature = 80 + Math.random() * 10;
    vibration = Math.floor(2 + Math.random() * 2);
    floww = 50 + Math.random() * 10;
} else {
    pressure = 690 + Math.random() * 40;
    temperature = 100 + Math.random() * 15;
    vibration = Math.floor(8 + Math.random() * 4);
    floww = 15 + Math.random() * 15;
}

msg.topic = "cursoiot/well1/sensor";

// Token de seguridad (debe coincidir con env WELL_TOKEN)
let token = env.get("WELL_TOKEN") || "well01-secret-2024";

msg.payload = JSON.stringify({
    well_id: "WELL-01",
    token: token,
    pressure: pressure,
    temperature: temperature,
    vibration: vibration,
    floww: floww
});

return msg;

let p = msg.payload;

if (!p || !p.status) {
    return null;
}

msg.payload = {
    status: p.status,
    confidence: p.confidence || 0,
    raw: p.nn_output || {}
};

return msg;

let p = msg.payload;
let f = p.features || {};

msg.payload = {
    pozo_id: p.well_id || "WELL-01",
    timestamp: new Date(p.timestamp).toISOString(),
    clasificacion_IA: {
        estado: p.status,
        confianza: Math.round((p.confidence || 0) * 100) + "%",
        probabilidades: {
            normal: Math.round(((p.nn_output && p.nn_output.normal) || 0) * 100) + "%",
            advertencia: Math.round(((p.nn_output && p.nn_output.warning) || 0) * 100) + "%",
            anomalia: Math.round(((p.nn_output && p.nn_output.anomaly) || 0) * 100) + "%"
        }
    },
    sensores: {
        presion_psi: {
            promedio: Math.round(f.pressure_avg || 0),
            desviacion: Math.round((f.pressure_std || 0) * 10) / 10,
            minimo: Math.round(f.pressure_min || 0),
            maximo: Math.round(f.pressure_max || 0),
            tendencia: Math.round(f.pressure_trend || 0)
        },
        temperatura_C: {
            promedio: Math.round((f.temperature_avg || 0) * 10) / 10,
            desviacion: Math.round((f.temperature_std || 0) * 10) / 10,
            minimo: Math.round((f.temperature_min || 0) * 10) / 10,
            maximo: Math.round((f.temperature_max || 0) * 10) / 10,
            tendencia: Math.round((f.temperature_trend || 0) * 10) / 10
        },
        vibracion_mmps: {
            promedio: Math.round((f.vibration_avg || 0) * 100) / 100,
            desviacion: Math.round((f.vibration_std || 0) * 100) / 100,
            minimo: Math.round((f.vibration_min || 0) * 100) / 100,
            maximo: Math.round((f.vibration_max || 0) * 100) / 100,
            tendencia: Math.round((f.vibration_trend || 0) * 100) / 100
        },
        flujo_bbldia: {
            promedio: Math.round((f.flow_avg || 0) * 10) / 10,
            desviacion: Math.round((f.flow_std || 0) * 10) / 10,
            minimo: Math.round((f.flow_min || 0) * 10) / 10,
            maximo: Math.round((f.flow_max || 0) * 10) / 10,
            tendencia: Math.round((f.flow_trend || 0) * 10) / 10
        }
    }
};

return msg;

// Status-change gate: sends to Gemini only after 3 consecutive
// confirmations of a status that differs from the last sent status.

let incoming = msg.payload.status;
if (!incoming) return null;

let buf      = flow.get("statusBuf")      || { status: null, count: 0 };
let lastSent = flow.get("lastSentStatus") || null;

if (incoming === buf.status) {
    buf.count++;
} else {
    buf = { status: incoming, count: 1 };
}
flow.set("statusBuf", buf);

// Fire only when confirmed 3x in a row AND it is a new status vs last sent
if (buf.count >= 3 && incoming !== lastSent) {
    flow.set("lastSentStatus", incoming);
    node.log("Status gate fired: " + lastSent + " -> " + incoming + " (confirmed " + buf.count + "x)");
    return msg;
}

return null;

if (msg.trainData) {
    flow.set("nnReady", true);
    flow.set("evalPredictions", []);
    node.log("MLP training complete -- inference enabled, starting holdout eval");
    node.send([null, { _evalTrigger: true }, null]);
    return null;
}
if (msg._isEval) {
    node.send([null, null, msg]);
    return null;
}
node.send([msg, null, null]);
return null;

let evalSet = flow.get("evalSet") || [];
if (evalSet.length === 0) { node.warn("No eval set in flow context"); return null; }
flow.set("evalPredictions", []);
node.log("Running holdout eval on " + evalSet.length + " samples");
evalSet.forEach(function(sample) {
    node.send({
        runData: sample.input,
        _isEval: true,
        _evalLabel: Object.keys(sample.output).find(function(k) { return sample.output[k] === 1; }),
        _evalTotal: evalSet.length
    });
});
return null;

let dec = msg.decision;
if (!dec) return null;

let pred = null, bestScore = -Infinity;
Object.keys(dec).forEach(function(k) {
    if (dec[k] !== null && dec[k] > bestScore) { bestScore = dec[k]; pred = k; }
});
if (!pred) return null;

let preds = flow.get("evalPredictions") || [];
preds.push({ pred: pred, label: msg._evalLabel });
flow.set("evalPredictions", preds);

let total = msg._evalTotal;
if (preds.length < total) {
    node.status({ fill: "yellow", shape: "dot", text: "Evaluating " + preds.length + "/" + total });
    return null;
}

let correct = preds.filter(function(p) { return p.pred === p.label; }).length;
let accuracy = correct / total;

let classes = ["normal", "anomaly"];
let recalls = [];
classes.forEach(function(cls) {
    let support = preds.filter(function(p) { return p.label === cls; }).length;
    if (support === 0) return;
    let tp = preds.filter(function(p) { return p.label === cls && p.pred === cls; }).length;
    recalls.push(tp / support);
});
let balAcc = recalls.length > 0 ? recalls.reduce(function(s, r) { return s + r; }, 0) / recalls.length : 0;

let result = {
    accuracy:          (accuracy * 100).toFixed(1) + "%",
    balanced_accuracy: (balAcc   * 100).toFixed(1) + "%",
    correct: correct,
    samples: total
};
node.log("Holdout eval: " + JSON.stringify(result));
node.status({ fill: "blue", shape: "dot", text: "Acc " + result.accuracy + " | Bal " + result.balanced_accuracy });
msg.payload = result;
return msg;

if (!flow.get("nnReady")) return null;
if (!msg._trueLabel) return null;

let trueLabel = msg._trueLabel;
let predicted = msg.payload && msg.payload.status;
if (!predicted) return null;

// Update running confusion matrix stored in flow context.
// Structure: { normal: {normal,warning,anomaly}, warning: {...}, anomaly: {...} }
let cm = flow.get("liveCM") || {
    normal:  { normal: 0, anomaly: 0 },
    anomaly: { normal: 0, anomaly: 0 }
};
if (!cm[trueLabel]) cm[trueLabel] = { normal: 0, anomaly: 0 };
cm[trueLabel][predicted] = (cm[trueLabel][predicted] || 0) + 1;
flow.set("liveCM", cm);

// Accuracy: correct / total predictions
let total   = 0, correct = 0;
Object.keys(cm).forEach(function(tl) {
    Object.keys(cm[tl]).forEach(function(pl) {
        total   += cm[tl][pl];
        if (tl === pl) correct += cm[tl][pl];
    });
});
let accuracy = total > 0 ? correct / total : 0;

// Balanced accuracy: average per-class recall (only for classes with support)
let classes = ["normal", "anomaly"];
let recalls = [];
classes.forEach(function(cls) {
    let row = cm[cls];
    if (!row) return;
    let support = Object.values(row).reduce(function(s, v) { return s + v; }, 0);
    if (support === 0) return;
    recalls.push((row[cls] || 0) / support);
});
let balAcc = recalls.length > 0
    ? recalls.reduce(function(s, r) { return s + r; }, 0) / recalls.length
    : 0;

let result = {
    accuracy:          (accuracy * 100).toFixed(1) + "%",
    balanced_accuracy: (balAcc   * 100).toFixed(1) + "%",
    total:   total,
    correct: correct,
    true_label: trueLabel,
    predicted:  predicted,
    confusion_matrix: cm
};

node.status({ fill: "green", shape: "dot",
    text: "Acc " + result.accuracy + " | Bal " + result.balanced_accuracy + " (" + total + " samples)" });

msg.payload = result;
return msg;
